import {{ Injectable }} from '@nestjs/common';
import {{ HealthService }} from './models/health.model';
import {{ HealthServiceRepository }} from './repositories/health.repository';

@Injectable()
export class HealthServiceService {{
  constructor(
    private readonly repository: HealthServiceRepository,
  ) {{}}

  async findAll(): Promise<HealthService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<HealthService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<HealthService>): Promise<HealthService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<HealthService>): Promise<HealthService> {{
    return this.repository.update(id, data);
  }}
}}

